import asyncioimport osimport pytestfrom langchain_anthropic import ChatAnthropicfrom langchain_community.document_loaders import DirectoryLoader, Docx2txtLoaderfrom langchain_community.embeddings import HuggingFaceEmbeddingsfrom ragas.embeddings import LangchainEmbeddingsWrapperfrom ragas.llms import LangchainLLMWrapperfrom ragas.testset import TestsetGeneratorasync def test_dataset_generation():    if not os.getenv("ANTHROPIC_API_KEY"):        pytest.skip("ANTHROPIC_API_KEY is not set")    model_name = os.getenv("ANTHROPIC_MODEL", "claude-sonnet-4-6")    print(f"Using Anthropic model: {model_name}", flush=True)    llm_model = ChatAnthropic(temperature=0, model_name=model_name)    langchain_llm = LangchainLLMWrapper(llm_model)    embed = HuggingFaceEmbeddings(model_name="all-MiniLM-L6-v2")    loader = DirectoryLoader(        path="/Users/srisatyakalyankallepalli/Downloads/fs11/",        glob="**/*.docx",        loader_cls=Docx2txtLoader    )    documents = loader.load()    generate_embeddings = LangchainEmbeddingsWrapper(embed)    generator = TestsetGenerator(llm=langchain_llm, embedding_model=generate_embeddings)    dataset = generator.generate_with_langchain_docs(documents, testset_size=20)    print(dataset.to_list())